import Card from "../components/ui/Card";
import Btn from "../components/ui/Btn";
import Icon from "../components/ui/Icon";

const RoomCard = ({ room, onAssign, onVacate, isAdmin, currentStudentId }) => {
  const avail = room.capacity - room.occupants.length;
  const full = avail === 0;
  const myRoom = !isAdmin && room.occupants.includes(currentStudentId);

  return (
    <Card style={{
      padding: 20,
      border: full ? "1.5px solid #fecaca" : myRoom ? "1.5px solid #86efac" : "1.5px solid #e2e8f0"
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
        <div>
          <div style={{ fontWeight: 800, fontSize: 18, color: "#1e293b" }}>{room.id}</div>
          <div style={{ fontSize: 13, color: "#64748b", marginTop: 2 }}>Block {room.block} · Floor {room.floor}</div>
        </div>
        <span style={{ background: full ? "#fee2e2" : myRoom ? "#dcfce7" : "#dbeafe", color: full ? "#b91c1c" : myRoom ? "#15803d" : "#1d4ed8", padding: "3px 10px", borderRadius: 99, fontSize: 12, fontWeight: 600 }}>
          {full ? "Full" : myRoom ? "Your Room" : `${avail} slot${avail > 1 ? "s" : ""} free`}
        </span>
      </div>
      <div style={{ marginTop: 12, display: "flex", gap: 8, flexWrap: "wrap" }}>
        <span style={{ background: "#ede9fe", color: "#6d28d9", padding: "3px 10px", borderRadius: 99, fontSize: 12, fontWeight: 600 }}>{room.type}</span>
        <span style={{ background: "#f1f5f9", color: "#475569", padding: "3px 10px", borderRadius: 99, fontSize: 12, fontWeight: 600 }}>Capacity: {room.capacity}</span>
        <span style={{ background: "#f1f5f9", color: "#475569", padding: "3px 10px", borderRadius: 99, fontSize: 12, fontWeight: 600 }}>Occupants: {room.occupants.length}</span>
      </div>
      <div style={{ marginTop: 16, display: "flex", gap: 8 }}>
        {isAdmin && !full && (
          <Btn onClick={() => onAssign(room.id)} style={{ fontSize: 12, padding: "7px 14px" }}>
            <Icon name="plus" size={14} /> Assign
          </Btn>
        )}
        {isAdmin && room.occupants.length > 0 && (
          <Btn variant="danger" onClick={() => onVacate(room.id)} style={{ fontSize: 12, padding: "7px 14px" }}>
            <Icon name="trash" size={14} /> Vacate
          </Btn>
        )}
        {!isAdmin && !myRoom && !full && (
          <Btn onClick={() => onAssign(room.id)} style={{ fontSize: 12, padding: "7px 14px" }}>
            Request Room
          </Btn>
        )}
      </div>
    </Card>
  );
};

const RoomsPage = ({ rooms, isAdmin, onAssign, onVacate, currentStudentId }) => {
  return (
    <div>
      <h2 style={{ fontSize: 22, fontWeight: 800, color: "#1e293b", marginBottom: 24 }}>🏠 Rooms</h2>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 16 }}>
        {rooms.map(room => (
          <RoomCard key={room.id} room={room} isAdmin={isAdmin}
            onAssign={onAssign} onVacate={onVacate} currentStudentId={currentStudentId} />
        ))}
      </div>
    </div>
  );
};

export default RoomsPage;
